patches.new_code:
h1 {
    color: #212529;
    margin: 15px 0;
    font-size: 1.6rem;
    text-align: center;
    display: flex; 
    align-items: center; 
    justify-content: center; 
    gap: 10px;
}

#help-btn {
    font-size: 1.1rem;
    font-weight: bold;
    color: #007bff;
    background-color: #e8f4fd;
    border: 1px solid #007bff;
    border-radius: 50%;
    width: 32px;
    height: 32px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

/* Modal Styles */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0,0,0,0.6);
    display: none; /* Hidden by default */
    justify-content: center;
    align-items: center;
    z-index: 1000;
}
.modal-content {
    background: #fff;
    padding: 25px;
    border-radius: 12px;
    box-shadow: 0 5px 15px rgba(0,0,0,0.3);
    width: 90%;
    max-width: 500px;
    position: relative;
}
.modal-close-btn {
    position: absolute;
    top: 10px;
    right: 15px;
    font-size: 1.8rem;
    font-weight: bold;
    cursor: pointer;
    color: #aaa;
    border: none;
    background: none;
}
.modal-close-btn:hover {
    color: #333;
}
.modal-content h3 {
    margin-top: 0;
    color: #007bff;
    border-bottom: 2px solid #e9ecef;
    padding-bottom: 10px;
    font-size: 1.3rem;
}
.command-list {
    list-style: none;
    padding: 0;
    margin: 0;
}
.command-list li {
    display: flex;
    gap: 15px;
    padding: 12px 5px;
    border-bottom: 1px solid #f1f3f5;
}
.command-list li:last-child {
    border-bottom: none;
}
.command-key {
    font-weight: 600;
    color: #dc3545;
    flex-basis: 150px; /* 명령어 너비 고정 */
    flex-shrink: 0; /* 줄어들지 않도록 설정 */
    font-family: monospace;
    font-size: 1rem;
}
.command-desc {
    color: #495057;
}

